import axios from "axios";
const url = "http://localhost:8080/api/robotApi";

// פונקציה אחת ויחידה להמרת שם התמונה לכתובת URL
export const getImageUrl = (img) => {
    // אם אין תמונה או שהיא לא הגיעה כטקסט
    if (!img || typeof img !== 'string' || img === "undefined") {
        return "https://via.placeholder.com/150?text=No+Image";
    }

    // ניקוי מירכאות מיותרות ורווחים
    let cleanImg = img.replace(/['"]+/g, '').trim();

    // מקרה א': תמונה ישנה מהאינטרנט (מתחילה ב-http)
    if (cleanImg.startsWith('http')) {
        return cleanImg;
    }

    // מקרה ב': תמונה חדשה מהשרת שלך (נמצאת בתיקיית image)
    // חייב להוסיף /image/ בנתיב
    return `http://localhost:8080/image/${encodeURIComponent(cleanImg)}`;
};

// שליפת כל הרובוטים
export const getAll = async () => {
    try {
        const { data } = await axios.get(`${url}/getAllRobots`);
        return data;
    } catch (e) {
        console.error("שגיאה בשליפת רובוטים:", e);
        return [];
    }
};

// שליפת רובוט לפי ID
export const getById = async (id) => {
    try {
        const { data } = await axios.get(`${url}/getRobotById/${id}`);
        return data;
    } catch (e) {
        console.error("שגיאה בשליפת רובוט:", e);
    }
};

// הוספת רובוט
export const addRobot = async (formData) => {
    try {
        const { data } = await axios.post(`${url}/postRobot`, formData);
        return data;
    } catch (e) {
        console.error("שגיאה בהוספת רובוט:", e);
    }
};
